package com.securestack.controller;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;import org.springframework.http.*;import java.util.*;import com.securestack.dto.Dto.*;import com.securestack.service.ScanService;import com.securestack.report.ReportService;@RestController@RequestMapping("/api") public class ApiController{private final ScanService scans;private final ReportService reports;ApiController(ScanService s,ReportService r){scans=s;reports=r;}@GetMapping("/health") Map<String,String> health(){return Map.of("status","ok","service","securestack-ai","version","1.0.0");}@PostMapping(value="/scans",consumes=MediaType.MULTIPART_FORM_DATA_VALUE) CreateScanResponse create(@RequestParam(required=false)String scanName,@RequestParam(defaultValue="STANDARD")String reviewDepth,@RequestParam(required=false)String focusAreas,@RequestParam(defaultValue="false")boolean generatePdf,@RequestPart(required=false)MultipartFile[] files,@RequestParam(required=false)String pastedFiles)throws Exception{return scans.create(scanName,reviewDepth,pastedFiles,files,generatePdf);}@GetMapping("/scans/{id}") ScanResultDto get(@PathVariable UUID id){return scans.get(id);}@GetMapping("/scans") List<ScanListItem> list(){return scans.list();}@PatchMapping("/scans/{sid}/findings/{fid}") void update(@PathVariable UUID sid,@PathVariable UUID fid,@RequestBody UpdateFindingStatusRequest r){scans.update(sid,fid,r.status());}@GetMapping("/scans/{id}/report") ResponseEntity<byte[]> report(@PathVariable UUID id){return ResponseEntity.ok().header(HttpHeaders.CONTENT_DISPOSITION,"attachment; filename=securestack-report.pdf").contentType(MediaType.APPLICATION_PDF).body(reports.pdf(id));}@ExceptionHandler(Exception.class) ResponseEntity<ErrorResponse> err(Exception e){return ResponseEntity.badRequest().body(new ErrorResponse("VALIDATION_ERROR",e.getMessage(),List.of()));}}
